const REGIONS = [
  "All",
  "Africa",
  "Europe",
  "Asia",
  "Americas",
  "Oceania",
  "Middle East",
];
const DC = { Easy: "#22c55e", Medium: "#eab308", Hard: "#ef4444" };

export default function App() {
  const [sel, setSel] = useState(null);
  const [q, setQ] = useState("");
  const [reg, setReg] = useState("All");
  const [hov, setHov] = useState(null);
  const [mode, setMode] = useState("map");
  const dataIds = new Set(Object.keys(COUNTRY_DATA).map(Number));

  const filtered = Object.entries(COUNTRY_DATA).filter(
    ([, d]) =>
      d.name.toLowerCase().includes(q.toLowerCase()) &&
      (reg === "All" || d.region === reg),
  );

  const c = sel ? COUNTRY_DATA[sel] : null;

  return (
    <div
      style={{
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        background: "#080810",
        color: "#ddd8cc",
        fontFamily: "'IBM Plex Mono','Fira Code',monospace",
        overflow: "hidden",
      }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@300;400;500;600&family=Playfair+Display:wght@600;700;800&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        ::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:rgba(255,255,255,0.02)}::-webkit-scrollbar-thumb{background:rgba(255,255,255,0.1);border-radius:3px}
        @keyframes fu{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
        @keyframes gl{0%,100%{filter:drop-shadow(0 0 3px rgba(99,218,190,0.25))}50%{filter:drop-shadow(0 0 8px rgba(99,218,190,0.55))}}
        .gp{transition:fill .15s,stroke .15s;cursor:pointer}.gp:hover{fill:rgba(99,218,190,0.4)!important;stroke:rgba(99,218,190,0.7)!important;stroke-width:1.2!important}
        .gp.s{fill:rgba(99,218,190,0.5)!important;stroke:#63dabe!important;stroke-width:1.5!important;animation:gl 2.5s ease-in-out infinite}.gp.dim{opacity:.2}
        .cl{animation:fu .25s ease forwards;opacity:0}
        .tg{padding:3px 10px;border-radius:12px;font-size:10px;cursor:pointer;border:1px solid rgba(255,255,255,0.08);background:0;color:#8a8878;font-family:inherit;transition:all .15s;white-space:nowrap}
        .tg:hover{border-color:rgba(99,218,190,0.3);color:#bbb8a8}.tg.on{background:rgba(99,218,190,0.12);border-color:rgba(99,218,190,0.35);color:#63dabe}
        .li{padding:9px 14px;border-radius:8px;cursor:pointer;display:flex;align-items:center;gap:10px;border:1px solid transparent;transition:all .12s}
        .li:hover{background:rgba(99,218,190,0.06);border-color:rgba(99,218,190,0.15)}.li.s{background:rgba(99,218,190,0.1);border-color:rgba(99,218,190,0.25)}
      `}</style>
      <div
        style={{
          padding: "14px 18px 10px",
          borderBottom: "1px solid rgba(255,255,255,0.05)",
          flexShrink: 0,
          background:
            "linear-gradient(180deg,rgba(99,218,190,0.04) 0%,transparent 100%)",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <span style={{ fontSize: 24 }}>🌍</span>
          <div>
            <h1
              style={{
                fontSize: 18,
                fontFamily: "'Playfair Display',serif",
                fontWeight: 700,
                color: "#f0ede6",
              }}
            >
              GeoGuessr Meta Guide
            </h1>
            <p style={{ fontSize: 10, color: "#5e5d55" }}>
              {Object.keys(COUNTRY_DATA).length} countries · GeoTips + community
              meta
            </p>
          </div>
        </div>
        <div
          style={{
            display: "flex",
            gap: 6,
            marginTop: 8,
            alignItems: "center",
          }}
        >
          <div style={{ flex: 1, position: "relative" }}>
            <span
              style={{
                position: "absolute",
                left: 9,
                top: "50%",
                transform: "translateY(-50%)",
                fontSize: 13,
                opacity: 0.35,
              }}
            >
              ⌕
            </span>
            <input
              type="text"
              placeholder="search..."
              value={q}
              onChange={(e) => {
                setQ(e.target.value);
                if (e.target.value) setMode("list");
              }}
              style={{
                width: "100%",
                padding: "6px 10px 6px 28px",
                background: "rgba(255,255,255,0.04)",
                border: "1px solid rgba(255,255,255,0.07)",
                borderRadius: 7,
                color: "#ddd8cc",
                fontSize: 12,
                fontFamily: "inherit",
                outline: "none",
              }}
            />
          </div>
          <button
            onClick={() => setMode((m) => (m === "map" ? "list" : "map"))}
            style={{
              padding: "6px 12px",
              background:
                mode === "list"
                  ? "rgba(99,218,190,0.12)"
                  : "rgba(255,255,255,0.04)",
              border: `1px solid ${mode === "list" ? "rgba(99,218,190,0.3)" : "rgba(255,255,255,0.07)"}`,
              borderRadius: 7,
              color: mode === "list" ? "#63dabe" : "#8a8878",
              fontSize: 11,
              fontFamily: "inherit",
              cursor: "pointer",
            }}
          >
            {mode === "list" ? "🗺 Map" : "☰ List"}
          </button>
        </div>
        <div
          style={{ display: "flex", gap: 5, marginTop: 7, flexWrap: "wrap" }}
        >
          {REGIONS.map((r) => (
            <button
              key={r}
              className={`tg ${reg === r ? "on" : ""}`}
              onClick={() => setReg(r)}
            >
              {r}
            </button>
          ))}
        </div>
      </div>
      <div
        style={{
          flex: 1,
          display: "flex",
          flexDirection: "column",
          overflow: "hidden",
          minHeight: 0,
        }}
      >
        <div
          style={{
            flex: sel ? "0 0 38%" : "1 1 auto",
            minHeight: sel ? 160 : 200,
            overflow: mode === "list" ? "auto" : "hidden",
            transition: "flex .3s",
            position: "relative",
          }}
        >
          {mode === "map" ? (
            <svg
              viewBox="0 0 960 500"
              style={{ width: "100%", height: "100%", display: "block" }}
              preserveAspectRatio="xMidYMid meet"
            >
              <path
                d={MAP.g}
                fill="none"
                stroke="rgba(255,255,255,0.025)"
                strokeWidth={0.5}
              />
              {Object.entries(MAP.p).map(([id, d]) => {
                const nid = +id,
                  has = dataIds.has(nid),
                  data = COUNTRY_DATA[nid];
                const isSel = sel === nid,
                  isHov = hov === nid;
                const match =
                  data &&
                  (reg === "All" || data.region === reg) &&
                  data.name.toLowerCase().includes(q.toLowerCase());
                return (
                  <path
                    key={id}
                    d={d}
                    className={`gp ${isSel ? "s" : ""} ${has && !match ? "dim" : ""}`}
                    fill={
                      !has
                        ? "rgba(255,255,255,0.035)"
                        : isSel
                          ? "rgba(99,218,190,0.5)"
                          : isHov
                            ? "rgba(99,218,190,0.3)"
                            : match
                              ? "rgba(99,218,190,0.1)"
                              : "rgba(255,255,255,0.035)"
                    }
                    stroke={
                      isSel
                        ? "#63dabe"
                        : has && match
                          ? "rgba(99,218,190,0.18)"
                          : "rgba(255,255,255,0.05)"
                    }
                    strokeWidth={isSel ? 1.5 : 0.35}
                    onClick={() => has && match && setSel(nid)}
                    onMouseEnter={() => has && match && setHov(nid)}
                    onMouseLeave={() => setHov(null)}
                  />
                );
              })}
              {hov && COUNTRY_DATA[hov] && MAP.c[hov] && (
                <g>
                  <rect
                    x={MAP.c[hov][0] - 55}
                    y={MAP.c[hov][1] - 24}
                    width={110}
                    height={20}
                    rx={5}
                    fill="rgba(8,8,16,0.93)"
                    stroke="rgba(99,218,190,0.3)"
                    strokeWidth={0.7}
                  />
                  <text
                    x={MAP.c[hov][0]}
                    y={MAP.c[hov][1] - 11}
                    textAnchor="middle"
                    fill="#ddd8cc"
                    fontSize={10}
                    fontFamily="'IBM Plex Mono',monospace"
                  >
                    {COUNTRY_DATA[hov].flag} {COUNTRY_DATA[hov].name}
                  </text>
                </g>
              )}
            </svg>
          ) : (
            <div style={{ padding: "8px 14px" }}>
              {filtered.length === 0 ? (
                <div
                  style={{ textAlign: "center", padding: 30, color: "#5e5d55" }}
                >
                  No matches
                </div>
              ) : (
                filtered.map(([id, d]) => (
                  <div
                    key={id}
                    className={`li ${sel === +id ? "s" : ""}`}
                    onClick={() => setSel(+id)}
                  >
                    <span style={{ fontSize: 18 }}>{d.flag}</span>
                    <div style={{ flex: 1 }}>
                      <div
                        style={{
                          fontSize: 12,
                          fontWeight: 500,
                          color: "#e8e5dd",
                        }}
                      >
                        {d.name}
                      </div>
                      <div style={{ fontSize: 9, color: "#5e5d55" }}>
                        {d.region} · {d.clues.length} clues · drives {d.side}
                      </div>
                    </div>
                    <span
                      style={{
                        fontSize: 9,
                        padding: "2px 7px",
                        borderRadius: 8,
                        background: `${DC[d.diff]}18`,
                        color: DC[d.diff],
                        border: `1px solid ${DC[d.diff]}30`,
                      }}
                    >
                      {d.diff}
                    </span>
                  </div>
                ))
              )}
            </div>
          )}
          {!sel && mode === "map" && (
            <div
              style={{
                position: "absolute",
                bottom: 10,
                left: "50%",
                transform: "translateX(-50%)",
                padding: "5px 14px",
                background: "rgba(8,8,16,0.8)",
                border: "1px solid rgba(255,255,255,0.06)",
                borderRadius: 16,
                fontSize: 10,
                color: "#5e5d55",
              }}
            >
              click any highlighted country
            </div>
          )}
        </div>
        {sel && c && (
          <div
            style={{
              flex: "1 1 62%",
              overflow: "auto",
              borderTop: "1px solid rgba(255,255,255,0.06)",
              background:
                "linear-gradient(180deg,rgba(99,218,190,0.015) 0%,transparent 40%)",
              minHeight: 0,
            }}
          >
            <div
              style={{
                padding: "12px 16px",
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
                borderBottom: "1px solid rgba(255,255,255,0.04)",
                position: "sticky",
                top: 0,
                background: "rgba(8,8,16,0.96)",
                backdropFilter: "blur(10px)",
                zIndex: 5,
              }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <span style={{ fontSize: 28 }}>{c.flag}</span>
                <div>
                  <h2
                    style={{
                      fontSize: 20,
                      fontFamily: "'Playfair Display',serif",
                      fontWeight: 700,
                      color: "#f0ede6",
                    }}
                  >
                    {c.name}
                  </h2>
                  <div
                    style={{
                      display: "flex",
                      gap: 6,
                      marginTop: 2,
                      flexWrap: "wrap",
                    }}
                  >
                    <span
                      style={{
                        fontSize: 9,
                        padding: "1px 7px",
                        borderRadius: 8,
                        background: "rgba(255,255,255,0.05)",
                        color: "#8a8878",
                      }}
                    >
                      {c.region}
                    </span>
                    <span
                      style={{
                        fontSize: 9,
                        padding: "1px 7px",
                        borderRadius: 8,
                        background: `${DC[c.diff]}15`,
                        color: DC[c.diff],
                        border: `1px solid ${DC[c.diff]}28`,
                      }}
                    >
                      {c.diff}
                    </span>
                    <span
                      style={{
                        fontSize: 9,
                        padding: "1px 7px",
                        borderRadius: 8,
                        background: "rgba(255,255,255,0.05)",
                        color: "#8a8878",
                      }}
                    >
                      drives {c.side}
                    </span>
                  </div>
                </div>
              </div>
              <button
                onClick={() => setSel(null)}
                style={{
                  width: 28,
                  height: 28,
                  borderRadius: "50%",
                  border: "1px solid rgba(255,255,255,0.1)",
                  background: "rgba(255,255,255,0.03)",
                  color: "#8a8878",
                  cursor: "pointer",
                  fontSize: 15,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontFamily: "inherit",
                }}
              >
                ×
              </button>
            </div>
            <div style={{ padding: "10px 14px 20px" }}>
              {c.clues.map((cl, i) => {
                const u = cl.t === "🎯";
                return (
                  <div
                    key={i}
                    className="cl"
                    style={{
                      padding: "11px 13px",
                      marginBottom: 5,
                      background: u
                        ? "rgba(99,218,190,0.035)"
                        : "rgba(255,255,255,0.012)",
                      border: `1px solid ${u ? "rgba(99,218,190,0.1)" : "rgba(255,255,255,0.035)"}`,
                      borderRadius: 8,
                      animationDelay: `${i * 0.035}s`,
                      borderLeft: u
                        ? "3px solid rgba(99,218,190,0.4)"
                        : "3px solid transparent",
                    }}
                  >
                    <span
                      style={{
                        fontSize: 10,
                        fontWeight: 600,
                        color: u ? "#63dabe" : "#8a8878",
                        letterSpacing: "0.7px",
                      }}
                    >
                      {cl.t === "🎯" ? "🎯 UNIQUE CLUE" : cl.t + " CLUE"}
                    </span>
                    <p
                      style={{
                        marginTop: 3,
                        fontSize: 12.5,
                        lineHeight: 1.55,
                        color: u ? "#d0cdbe" : "#a8a598",
                        fontFamily: "'IBM Plex Mono',monospace",
                        fontWeight: u ? 400 : 300,
                      }}
                    >
                      {cl.s}
                    </p>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
